@page "/tickets"
@rendermode InteractiveServer
@inject ITicketService TicketService

<PageTitle>Help Desk - Tickets</PageTitle>

<div class="tickets-dashboard">
    <!-- Top Bar -->
    <div class="top-bar">
        <div class="search-box">
            <input type="text" class="form-control" placeholder="Search tickets by subject..."
                   @bind="searchQuery" @bind:event="oninput" @onkeyup="OnSearchKeyUp" />
        </div>
        <div class="status-tabs">
            @foreach (var tab in statusTabs)
            {
                <button class="btn tab-btn @(statusFilter == tab.Value ? "active" : "")"
                        @onclick="() => SetStatusFilter(tab.Value)">
                    @tab.Label
                </button>
            }
        </div>
        <div class="priority-filter">
            <select class="form-select" @onchange="OnPriorityFilterChanged">
                @foreach (var p in priorityOptions)
                {
                    <option value="@p.Value" selected="@(priorityFilter == p.Value)">@p.Label</option>
                }
            </select>
        </div>
    </div>

    <!-- Main Panels -->
    <div class="panels">
        <!-- Left Panel -->
        <div class="left-panel">
            @if (tickets is null)
            {
                <div class="loading-placeholder">Loading tickets...</div>
            }
            else if (tickets.Count == 0)
            {
                <div class="loading-placeholder">No tickets found.</div>
            }
            else
            {
                @foreach (var ticket in tickets)
                {
                    <div class="ticket-card @(selectedTicket?.Id == ticket.Id ? "active" : "")"
                         @onclick="() => SelectTicket(ticket)">
                        <div class="ticket-card-header">
                            <span class="priority-dot @GetPriorityClass(ticket.Priority)"></span>
                            <span class="ticket-subject">@ticket.Subject</span>
                        </div>
                        <div class="ticket-card-meta">
                            <span class="ticket-requester">@ticket.Requester</span>
                            <span class="ticket-time">@GetRelativeTime(ticket.CreatedAt)</span>
                        </div>
                        <div class="ticket-card-footer">
                            <span class="status-badge badge @GetStatusBadgeClass(ticket.Status)">@ticket.Status</span>
                        </div>
                    </div>
                }
            }
        </div>

        <!-- Right Panel -->
        <div class="right-panel">
            @if (selectedTicket is null)
            {
                <div class="no-selection">Select a ticket to view details</div>
            }
            else
            {
                <div class="detail-header">
                    <h4 class="detail-subject">@selectedTicket.Subject</h4>
                    <div class="detail-controls">
                        <select class="form-select form-select-sm status-select" value="@selectedTicket.Status"
                                @onchange="OnStatusChanged">
                            <option value="Open">Open</option>
                            <option value="In Progress">In Progress</option>
                            <option value="Resolved">Resolved</option>
                        </select>
                        <span class="badge @GetPriorityBadgeClass(selectedTicket.Priority)">@selectedTicket.Priority</span>
                    </div>
                    <div class="detail-opener">
                        Opened by <strong>@selectedTicket.Requester</strong> on @selectedTicket.CreatedAt.ToString("MMMM d, yyyy")
                    </div>
                </div>

                <div class="detail-body">
                    <p>@selectedTicket.Description</p>
                </div>

                <div class="comment-section">
                    <h5>Comments</h5>
                    @if (comments is null)
                    {
                        <p class="text-muted">Loading comments...</p>
                    }
                    else if (comments.Count == 0)
                    {
                        <p class="text-muted">No comments yet.</p>
                    }
                    else
                    {
                        @foreach (var comment in comments)
                        {
                            <div class="comment-item">
                                <div class="comment-header">
                                    <strong>@comment.Author</strong>
                                    <span class="comment-time">@comment.PostedAt.ToString("MMM d, yyyy h:mm tt")</span>
                                </div>
                                <div class="comment-text">@comment.Text</div>
                            </div>
                        }
                    }

                    <div class="add-comment">
                        <textarea class="form-control" rows="3" placeholder="Write a comment..."
                                  @bind="newCommentText"></textarea>
                        <button class="btn btn-primary mt-2" @onclick="SubmitComment"
                                disabled="@string.IsNullOrWhiteSpace(newCommentText)">
                            Submit
                        </button>
                    </div>
                </div>
            }
        </div>
    </div>

    <!-- Footer Bar -->
    <div class="footer-bar">
        @if (tickets is not null)
        {
            var openCount = tickets.Count(t => t.Status == "Open");
            var inProgressCount = tickets.Count(t => t.Status == "In Progress");
            var resolvedCount = tickets.Count(t => t.Status == "Resolved");
            <span>@openCount open · @inProgressCount in progress · @resolvedCount resolved</span>
        }
    </div>
</div>

@code {
    private List<Ticket>? tickets;
    private List<Comment>? comments;
    private Ticket? selectedTicket;
    private string? searchQuery;
    private string? statusFilter;
    private string? priorityFilter;
    private string newCommentText = string.Empty;

    private readonly record struct FilterOption(string Label, string? Value);

    private static readonly FilterOption[] statusTabs =
    [
        new("All", null),
        new("Open", "Open"),
        new("In Progress", "In Progress"),
        new("Resolved", "Resolved")
    ];

    private static readonly FilterOption[] priorityOptions =
    [
        new("All Priorities", null),
        new("Critical", "Critical"),
        new("High", "High"),
        new("Medium", "Medium"),
        new("Low", "Low")
    ];

    protected override async Task OnInitializedAsync()
    {
        await LoadTickets();
    }

    private async Task LoadTickets()
    {
        tickets = await TicketService.GetTicketsAsync(statusFilter, priorityFilter, searchQuery);
    }

    private async Task SetStatusFilter(string? filter)
    {
        statusFilter = filter;
        await LoadTickets();
    }

    private async Task OnPriorityFilterChanged(ChangeEventArgs e)
    {
        var value = e.Value?.ToString();
        priorityFilter = string.IsNullOrEmpty(value) ? null : value;
        await LoadTickets();
    }

    private async Task OnSearchKeyUp(KeyboardEventArgs e)
    {
        await LoadTickets();
    }

    private async Task SelectTicket(Ticket ticket)
    {
        selectedTicket = ticket;
        newCommentText = string.Empty;
        comments = await TicketService.GetCommentsAsync(ticket.Id);
    }

    private async Task OnStatusChanged(ChangeEventArgs e)
    {
        if (selectedTicket is null) return;
        var newStatus = e.Value?.ToString();
        if (string.IsNullOrEmpty(newStatus) || newStatus == selectedTicket.Status) return;

        await TicketService.UpdateStatusAsync(selectedTicket.Id, newStatus);
        selectedTicket = selectedTicket with { Status = newStatus };
        await LoadTickets();
    }

    private async Task SubmitComment()
    {
        if (selectedTicket is null || string.IsNullOrWhiteSpace(newCommentText)) return;

        await TicketService.AddCommentAsync(selectedTicket.Id, newCommentText);
        newCommentText = string.Empty;
        comments = await TicketService.GetCommentsAsync(selectedTicket.Id);
    }

    private static string GetPriorityClass(string priority) => priority switch
    {
        "Critical" => "priority-critical",
        "High" => "priority-high",
        "Medium" => "priority-medium",
        "Low" => "priority-low",
        _ => "priority-low"
    };

    private static string GetPriorityBadgeClass(string priority) => priority switch
    {
        "Critical" => "bg-danger",
        "High" => "bg-warning text-dark",
        "Medium" => "bg-info text-dark",
        "Low" => "bg-secondary",
        _ => "bg-secondary"
    };

    private static string GetStatusBadgeClass(string status) => status switch
    {
        "Open" => "bg-primary",
        "In Progress" => "bg-warning text-dark",
        "Resolved" => "bg-success",
        _ => "bg-secondary"
    };

    private static string GetRelativeTime(DateTime createdAt)
    {
        var span = DateTime.UtcNow - createdAt;

        if (span.TotalMinutes < 1) return "just now";
        if (span.TotalMinutes < 60) return $"{(int)span.TotalMinutes} minutes ago";
        if (span.TotalHours < 24) return $"{(int)span.TotalHours} hours ago";
        if (span.TotalDays < 30) return $"{(int)span.TotalDays} days ago";
        if (span.TotalDays < 365) return $"{(int)(span.TotalDays / 30)} months ago";
        return $"{(int)(span.TotalDays / 365)} years ago";
    }
}

.tickets-dashboard {
    display: flex;
    flex-direction: column;
    height: 100vh;
}

/* Top Bar */
.top-bar {
    display: flex;
    align-items: center;
    gap: 1rem;
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #dee2e6;
    background: #f8f9fa;
    flex-wrap: wrap;
}

.search-box {
    flex: 1;
    min-width: 200px;
}

.status-tabs {
    display: flex;
    gap: 0.25rem;
}

.tab-btn {
    border: 1px solid #dee2e6;
    background: #fff;
    border-radius: 4px;
    padding: 0.375rem 0.75rem;
    font-size: 0.875rem;
    cursor: pointer;
}

.tab-btn.active {
    background: #0d6efd;
    color: #fff;
    border-color: #0d6efd;
}

.priority-filter {
    min-width: 160px;
}

/* Panels */
.panels {
    display: flex;
    flex: 1;
    overflow: hidden;
}

.left-panel {
    width: 40%;
    overflow-y: auto;
    border-right: 1px solid #dee2e6;
    background: #fff;
}

.right-panel {
    width: 60%;
    overflow-y: auto;
    padding: 1.5rem;
    background: #fdfdfd;
}

/* Ticket Card */
.ticket-card {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #eee;
    cursor: pointer;
    transition: background 0.15s;
}

.ticket-card:hover {
    background: #f0f4ff;
}

.ticket-card.active {
    background: #e2ecff;
    border-left: 3px solid #0d6efd;
}

.ticket-card-header {
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.priority-dot {
    width: 10px;
    height: 10px;
    border-radius: 50%;
    flex-shrink: 0;
}

.priority-critical {
    background-color: #dc3545;
}

.priority-high {
    background-color: #fd7e14;
}

.priority-medium {
    background-color: #ffc107;
}

.priority-low {
    background-color: #6c757d;
}

.ticket-subject {
    font-weight: 500;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    flex: 1;
}

.ticket-card-meta {
    display: flex;
    justify-content: space-between;
    font-size: 0.8rem;
    color: #6c757d;
    margin-top: 0.25rem;
}

.ticket-card-footer {
    margin-top: 0.35rem;
}

.status-badge {
    font-size: 0.7rem;
}

/* Right Panel Detail */
.no-selection {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #6c757d;
    font-size: 1.1rem;
}

.detail-header {
    margin-bottom: 1.25rem;
    padding-bottom: 1rem;
    border-bottom: 1px solid #dee2e6;
}

.detail-subject {
    margin-bottom: 0.5rem;
}

.detail-controls {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    margin-bottom: 0.5rem;
}

.status-select {
    width: auto;
    max-width: 160px;
}

.detail-opener {
    font-size: 0.875rem;
    color: #6c757d;
}

.detail-body {
    margin-bottom: 1.5rem;
    line-height: 1.6;
}

/* Comments */
.comment-section h5 {
    margin-bottom: 0.75rem;
}

.comment-item {
    padding: 0.6rem 0;
    border-bottom: 1px solid #eee;
}

.comment-header {
    display: flex;
    justify-content: space-between;
    font-size: 0.85rem;
    margin-bottom: 0.25rem;
}

.comment-time {
    color: #6c757d;
}

.comment-text {
    font-size: 0.9rem;
}

.add-comment {
    margin-top: 1rem;
}

/* Footer */
.footer-bar {
    padding: 0.5rem 1rem;
    border-top: 1px solid #dee2e6;
    background: #f8f9fa;
    font-size: 0.875rem;
    color: #495057;
}

/* Loading */
.loading-placeholder {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #6c757d;
    padding: 2rem;
}

