toolArgs.file_text:
.tickets-dashboard {
    display: flex;
    flex-direction: column;
    height: 100vh;
}

/* Top Bar */
.top-bar {
    display: flex;
    align-items: center;
    gap: 1rem;
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #dee2e6;
    background: #f8f9fa;
    flex-wrap: wrap;
}

.search-box {
    flex: 1;
    min-width: 200px;
}

.status-tabs {
    display: flex;
    gap: 0.25rem;
}

.tab-btn {
    border: 1px solid #dee2e6;
    background: #fff;
    border-radius: 4px;
    padding: 0.375rem 0.75rem;
    font-size: 0.875rem;
    cursor: pointer;
}

.tab-btn.active {
    background: #0d6efd;
    color: #fff;
    border-color: #0d6efd;
}

.priority-filter {
    min-width: 160px;
}

/* Panels */
.panels {
    display: flex;
    flex: 1;
    overflow: hidden;
}

.left-panel {
    width: 40%;
    overflow-y: auto;
    border-right: 1px solid #dee2e6;
    background: #fff;
}

.right-panel {
    width: 60%;
    overflow-y: auto;
    padding: 1.5rem;
    background: #fdfdfd;
}

/* Ticket Card */
.ticket-card {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #eee;
    cursor: pointer;
    transition: background 0.15s;
}

.ticket-card:hover {
    background: #f0f4ff;
}

.ticket-card.active {
    background: #e2ecff;
    border-left: 3px solid #0d6efd;
}

.ticket-card-header {
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.priority-dot {
    width: 10px;
    height: 10px;
    border-radius: 50%;
    flex-shrink: 0;
}

.priority-critical {
    background-color: #dc3545;
}

.priority-high {
    background-color: #fd7e14;
}

.priority-medium {
    background-color: #ffc107;
}

.priority-low {
    background-color: #6c757d;
}

.ticket-subject {
    font-weight: 500;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    flex: 1;
}

.ticket-card-meta {
    display: flex;
    justify-content: space-between;
    font-size: 0.8rem;
    color: #6c757d;
    margin-top: 0.25rem;
}

.ticket-card-footer {
    margin-top: 0.35rem;
}

.status-badge {
    font-size: 0.7rem;
}

/* Right Panel Detail */
.no-selection {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #6c757d;
    font-size: 1.1rem;
}

.detail-header {
    margin-bottom: 1.25rem;
    padding-bottom: 1rem;
    border-bottom: 1px solid #dee2e6;
}

.detail-subject {
    margin-bottom: 0.5rem;
}

.detail-controls {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    margin-bottom: 0.5rem;
}

.status-select {
    width: auto;
    max-width: 160px;
}

.detail-opener {
    font-size: 0.875rem;
    color: #6c757d;
}

.detail-body {
    margin-bottom: 1.5rem;
    line-height: 1.6;
}

/* Comments */
.comment-section h5 {
    margin-bottom: 0.75rem;
}

.comment-item {
    padding: 0.6rem 0;
    border-bottom: 1px solid #eee;
}

.comment-header {
    display: flex;
    justify-content: space-between;
    font-size: 0.85rem;
    margin-bottom: 0.25rem;
}

.comment-time {
    color: #6c757d;
}

.comment-text {
    font-size: 0.9rem;
}

.add-comment {
    margin-top: 1rem;
}

/* Footer */
.footer-bar {
    padding: 0.5rem 1rem;
    border-top: 1px solid #dee2e6;
    background: #f8f9fa;
    font-size: 0.875rem;
    color: #495057;
}

/* Loading */
.loading-placeholder {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #6c757d;
    padding: 2rem;
}

